2	//
3	// A model-friendly theme token template for scaffolded HarmonyOS apps.
4	//
5	// Agent rules:
6	// - Keep the exported class names as Theme and BrandGradient.
7	// - Prefer replacing token values instead of renaming widely used semantic tokens.
8	// - Keep layout contract tokens such as pageHorizontalPadding, bottomTabHeight,
9	// - contentMaxWidth, and touchTarget stable unless the app shell changes.
10	//
11	// Usage:
12	// - Replace color, radius, spacing, and gradient values to match the real brand.
13	// - If the project already has a design system, adapt this file to that system
14	// - while preserving the common semantic API used by scaffold components.
15	//
16	// Notes:
17	// - This file intentionally uses semantic token names instead of screen-specific names.
18	// - The default values are placeholders and should not be treated as product requirements.
19	export class Theme {
20	  static readonly pageBg: string = '#F6F1EA';
21	  static readonly cardBg: string = '#FFFFFF';
22	  static readonly brandPrimary: string = '#006F45';
23	  static readonly brandDark: string = '#0F3329';
