    } else if (v === 'contact') {
      return 'icon_查看应急联系人.svg';
    } else if (v === 'user') {
      return 'icon_打开个人中心.svg';
    } else if (v === 'add') {
      return 'icon_新增巡检任务.svg';
    }
    return 'icon_工作台标签.svg';
  }

  static spec(fileName: string): SvgStyleSpec | undefined {
    return SVG_STYLE_MAP[fileName];
