import { Theme } from '../common/Theme';

@Component
export struct EmptyStateView {
  @Prop title: string = '暂无数据';
  @Prop subtitle: string = '';

  build() {
    Column({ space: 8 }) {
      Text(this.title)
        .fontSize(16)
        .fontWeight(FontWeight.Medium)
        .fontColor(Theme.textTertiary)
      if (this.subtitle) {
        Text(this.subtitle)
          .fontSize(14)
          .fontColor(Theme.textQuaternary)
      }
    }
    .width('100%')
    .padding({ top: 32, bottom: 32 })
    .justifyContent(FlexAlign.Center)
    .alignItems(HorizontalAlign.Center)
  }
}

@Component
export struct SectionTitle {
  @Prop title: string = '';

  build() {
    Text(this.title)
      .fontSize(16)
      .fontWeight(FontWeight.SemiBold)
      .fontColor(Theme.textPrimary)
      .width('100%')
  }
}

@Component
export struct PrimaryButton {
  @Prop label: string = '保存';
  @Prop enabled: boolean = true;
  onClick?: () => void;

  build() {
    Button(this.label)
      .width('100%')
      .height(48)
      .fontSize(16)
      .fontWeight(FontWeight.SemiBold)
      .fontColor(Theme.textOnBrand)
      .backgroundColor(Theme.brandPrimary)
      .borderRadius(Theme.radiusButton)
      .shadow(this.enabled ? Theme.buttonShadow : { radius: 0, color: Color.Transparent, offsetY: 0 })
      .enabled(this.enabled)
      .onClick(() => {
        if (this.onClick) {
          this.onClick();
        }
      })
  }
}

@Component
export struct DangerButton {
  @Prop label: string = '删除';
  onClick?: () => void;

  build() {
    Button(this.label)
      .width('100%')
      .height(44)
      .fontSize(14)
      .fontWeight(FontWeight.Medium)
      .fontColor(Theme.danger)
      .backgroundColor(Theme.dangerSoft)
      .borderRadius(Theme.radiusButton)
      .onClick(() => {
        if (this.onClick) {
          this.onClick();
        }
      })
  }
}

@Component
export struct GhostButton {
  @Prop label: string = '';
  @Prop active: boolean = false;
  onClick?: () => void;

  build() {
    Button(this.label)
      .height(32)
      .padding({ left: 14, right: 14 })
      .fontSize(13)
      .fontWeight(FontWeight.Medium)
      .fontColor(this.active ? Theme.brandPrimary : Theme.textTertiary)
      .backgroundColor(this.active ? Theme.brandSoft : Theme.inputBg)
      .border({ width: 1, color: this.active ? Theme.brandPrimary : Theme.borderDefault })
      .borderRadius(Theme.radiusSmall)
      .onClick(() => {
        if (this.onClick) {
          this.onClick();
        }
      })
  }
}

@Component
export struct PageHeader {
  @Prop title: string = '';
  onBack?: () => void;
  @BuilderParam trailing: () => void = this.emptyBuilder;

  @Builder
  emptyBuilder() {}

  build() {
    Row() {
      Button() {
        Text('<')
          .fontSize(18)
          .fontWeight(FontWeight.Bold)
          .fontColor(Theme.textPrimary)
      }
      .width(40)
      .height(40)
      .backgroundColor(Color.Transparent)
      .onClick(() => {
        if (this.onBack) {
          this.onBack();
        }
      })

      Text(this.title)
        .fontSize(18)
        .fontWeight(FontWeight.SemiBold)
        .fontColor(Theme.textPrimary)
        .layoutWeight(1)
        .textAlign(TextAlign.Center)

      this.trailing()
    }
    .width('100%')
    .height(56)
    .padding({ left: 8, right: 8 })
    .backgroundColor(Theme.pageBg)
    .alignItems(VerticalAlign.Center)
  }
}

@Component
export struct FormField {
  @Prop label: string = '';
  @Prop placeholder: string = '';
  @Prop value: string = '';
  @Prop componentId: string = '';
  @Prop multiline: boolean = false;
  onChange?: (value: string) => void;

  build() {
    Column({ space: 6 }) {
      Text(this.label)
        .fontSize(14)
        .fontWeight(FontWeight.Medium)
        .fontColor(Theme.textSecondary)
        .width('100%')
      if (this.multiline) {
        TextArea({ text: this.value, placeholder: this.placeholder })
          .id(this.componentId)
          .width('100%')
          .height(120)
          .fontSize(14)
          .fontColor(Theme.textPrimary)
          .placeholderColor(Theme.textPlaceholder)
          .backgroundColor(Theme.inputBg)
          .border({ width: 1, color: Theme.borderDefault })
          .borderRadius(Theme.radiusPill)
          .padding(12)
          .onChange((v: string) => {
            if (this.onChange) {
              this.onChange(v);
            }
          })
      } else {
        TextInput({ text: this.value, placeholder: this.placeholder })
          .id(this.componentId)
          .width('100%')
          .height(48)
          .fontSize(14)
          .fontColor(Theme.textPrimary)
          .placeholderColor(Theme.textPlaceholder)
          .backgroundColor(Theme.inputBg)
          .border({ width: 1, color: Theme.borderDefault })
          .borderRadius(Theme.radiusPill)
          .padding({ left: 14, right: 14 })
          .onChange((v: string) => {
            if (this.onChange) {
              this.onChange(v);
            }
          })
      }
    }
    .width('100%')
    .alignItems(HorizontalAlign.Start)
  }
}

