1	import { Theme } from '../common/Theme';
2	import { ContactController } from '../controllers/ContactController';
3	import { Contact } from '../model/Contact';
4	import { PageHeader, FormField, PrimaryButton, DangerButton } from '../components/CommonUi';
5	import { promptAction } from '@kit.ArkUI';
6	
7	@Component
8	export struct ContactDetailPage {
9	  contactId: string = '';
10	  onBack?: () => void;
11	  @State draft: Contact = new Contact();
12	  private controller = new ContactController();
13	
14	  aboutToAppear(): void {
15	    if (this.contactId) {
16	      const found = this.controller.get(this.contactId);
17	      if (found) {
18	        this.draft = new Contact();
19	        this.draft.id = found.id;
20	        this.draft.name = found.name;
21	        this.draft.role = found.role;
22	        this.draft.department = found.department;
23	        this.draft.phone = found.phone;
24	        this.draft.isEmergency = found.isEmergency;
25	        this.draft.createdAt = found.createdAt;
26	        this.draft.updatedAt = found.updatedAt;
27	      } else {
28	        this.draft = this.controller.createDraft();
29	      }
30	    } else {
31	      this.draft = this.controller.createDraft();
32	    }
33	  }
34	
35	  private save(): void {
36	    if (!this.draft.name.trim() || !this.draft.phone.trim()) {
37	      promptAction.showToast({ message: '请填写姓名和电话' });
38	      return;
39	    }
40	    this.controller.save(this.draft);
41	    promptAction.showToast({ message: '已保存' });
42	    if (this.onBack) this.onBack();
43	  }
44	
45	  private delete(): void {
46	    if (this.contactId) {
47	      this.controller.delete(this.contactId);
48	      if (this.onBack) this.onBack();
49	    }
50	  }
51	
52	  build() {
53	    Column({ space: 0 }) {
54	      PageHeader({
55	        title: this.contactId ? '联系人详情' : '新建联系人',
56	        onBack: () => {
57	          if (this.onBack) this.onBack();
58	        },
59	        trailing: this.saveButton
60	      })
61	
62	      Scroll() {
63	        Column({ space: 16 }) {
64	          Column({ space: 16 }) {
65	            FormField({
66	              label: '姓名',
67	              placeholder: '请输入姓名',
68	              value: this.draft.name,
69	              componentId: 'contact-detail-name-input',
70	              onChange: (v) => this.draft.name = v
71	            })
72	            FormField({
73	              label: '角色',
74	              placeholder: '如：安全主管、消防负责人',
75	              value: this.draft.role,
76	              componentId: 'contact-detail-role-input',
77	              onChange: (v) => this.draft.role = v
78	            })
79	            FormField({
80	              label: '部门',
81	              placeholder: '请输入部门',
82	              value: this.draft.department,
83	              componentId: 'contact-detail-department-input',
84	              onChange: (v) => this.draft.department = v
85	            })
86	            FormField({
87	              label: '电话',
88	              placeholder: '请输入电话号码',
89	              value: this.draft.phone,
90	              componentId: 'contact-detail-phone-input',
91	              onChange: (v) => this.draft.phone = v
92	            })
93	
94	            Row({ space: 12 }) {
95	              Text('设为紧急联系人')
96	                .fontSize(14)
97	                .fontWeight(FontWeight.Medium)
98	                .fontColor(Theme.textSecondary)
99	                .layoutWeight(1)
100	              Toggle({ type: ToggleType.Switch, isOn: this.draft.isEmergency })
101	                .id('contact-detail-emergency-toggle')
102	                .selectedColor(Theme.danger)
103	                .onChange((isOn: boolean) => {
104	                  this.draft.isEmergency = isOn;
105	                })
106	            }
107	            .width('100%')
108	            .height(48)
109	          }
110	          .width('100%')
111	          .padding(16)
112	          .backgroundColor(Theme.cardBg)
113	          .borderRadius(Theme.radiusCard)
114	          .shadow(Theme.cardShadow)
115	
116	          if (this.contactId) {
117	            DangerButton({
118	              label: '删除联系人',
119	              onTap: () => this.delete()
120	            })
121	          }
122	
123	          Blank().height(24)
124	        }
125	        .width('100%')
126	        .padding(16)
127	        .padding({ bottom: 24 })
128	      }
129	      .width('100%')
130	      .layoutWeight(1)
131	      .scrollBar(BarState.Off)
132	
133	      Column() {
134	        PrimaryButton({
135	          label: '保存',
136	          onTap: () => this.save()
137	        })
138	          .id('contact-detail-save-button')
139	      }
140	      .width('100%')
141	      .padding(16)
142	      .backgroundColor(Theme.pageBg)
143	    }
144	    .width('100%')
145	    .height('100%')
146	    .backgroundColor(Theme.pageBg)
147	  }
148	
149	  @Builder
150	  saveButton() {
151	    Button('保存')
152	      .id('contact-detail-save-button')
153	      .fontSize(14)
154	      .fontWeight(FontWeight.Bold)
155	      .fontColor(Theme.brandPrimary)
156	      .backgroundColor(Color.Transparent)
157	      .onClick(() => this.save())
158	  }
159	}

